   1→use crate::context::{ContextConfig, compact_messages};
   2→use crate::error::CoreError;
   3→use crate::protocol::{
   4→    AgentEvent, ChatMessage, ModelDirective, ModelStopReason, ModelTurn, RunStopReason, TokenUsage,
   5→    ToolCall, ToolDefinition, ToolResult, ToolResultSummary,
   6→};
   7→use crate::state::AppState;
   8→use std::collections::BTreeMap;
   9→use std::sync::Arc;
  10→use std::sync::atomic::{AtomicBool, Ordering};
  11→
  12→/// A shared, swappable provider handle.
  13→///
  14→/// Uses `std::sync::RwLock` (not tokio) because providers use blocking I/O
  15→/// via `spawn_blocking`. Multiple readers can access concurrently; writes
  16→/// only hold the lock for the instant of swapping the inner `Arc`.
  17→pub type SwappableProviderHandle = Arc<std::sync::RwLock<Arc<dyn Provider>>>;
  18→
  19→/// Factory for building providers from a spec string at runtime.
  20→///
  21→/// The spec format is `"provider_name"` or `"provider_name:model"`.
  22→pub trait ProviderFactory: Send + Sync {
  23→    /// Build a new provider from a spec like `"anthropic"` or `"ollama:llama3.2"`.
  24→    fn build(&self, spec: &str) -> Result<Arc<dyn Provider>, CoreError>;
  25→
  26→    /// List the available provider names (e.g. `["anthropic", "openai", "ollama", "mock"]`).
  27→    fn available_providers(&self) -> Vec<String>;
  28→}
  29→
  30→/// Hook trait for approval gates, allowing the agent loop to wire event handlers
  31→/// into the gate without depending on the concrete `ApprovalGate` type.
  32→pub trait ApprovalGateHook: Send + Sync {
  33→    fn set_event_handler(&self, handler: Arc<dyn Fn(AgentEvent) + Send + Sync>);
  34→    fn clear_event_handler(&self);
  35→}
  36→
  37→/// Trait for resolving pending approvals from HTTP endpoints.
  38→pub trait ApprovalResolver: Send + Sync {
  39→    fn resolve_approval(&self, approval_id: &str, decision: &str, reason: Option<String>) -> bool;
  40→    fn pending_approval_ids(&self) -> Vec<String>;
  41→}
