  43→#[derive(Debug, Clone)]
  44→pub struct ProviderRequest {
  45→    pub run_id: String,
  46→    pub session_id: String,
  47→    pub iteration: u32,
  48→    pub messages: Vec<ChatMessage>,
  49→    pub tools: Vec<ToolDefinition>,
  50→    pub state: AppState,
  51→}
  52→
  53→pub trait Provider: Send + Sync {
  54→    fn name(&self) -> &str;
  55→    fn complete(&self, request: &ProviderRequest) -> Result<ModelTurn, CoreError>;
  56→
  57→    /// Whether this provider supports streaming completions.
  58→    fn supports_streaming(&self) -> bool {
  59→        false
  60→    }
  61→
  62→    /// Stream a completion, calling `on_text` for each text delta as it arrives.
  63→    /// Returns the final assembled `ModelTurn`. Default falls back to `complete()`.
  64→    fn complete_streaming(
  65→        &self,
  66→        request: &ProviderRequest,
  67→        _on_text: &dyn Fn(&str),
  68→    ) -> Result<ModelTurn, CoreError> {
  69→        self.complete(request)
  70→    }
  71→}
