  78→}
  79→
  80→pub trait Tool: Send + Sync {
  81→    fn definition(&self) -> ToolDefinition;
  82→    fn execute(&self, call: &ToolCall, ctx: &ToolContext) -> Result<ToolResult, CoreError>;
  83→}
  84→
  85→pub trait Middleware: Send + Sync {
  86→    fn before_model_call(&self, _request: &ProviderRequest) -> Result<(), CoreError> {
