  98→    fn pre_tool_call(&self, _context: &ToolContext, _call: &ToolCall) -> Result<(), CoreError> {
  99→        Ok(())
 100→    }
 101→
 102→    fn post_tool_call(
 103→        &self,
 104→        _context: &ToolContext,
