 115→#[derive(Clone, Default)]
 116→pub struct ToolRegistry {
 117→    tools: BTreeMap<String, Arc<dyn Tool>>,
 118→}
 119→
 120→impl ToolRegistry {
 121→    pub fn register<T: Tool + 'static>(&mut self, tool: T) {
 122→        self.tools
 123→            .insert(tool.definition().name.clone(), Arc::new(tool));
 124→    }
 125→
 126→    pub fn get(&self, tool_name: &str) -> Option<Arc<dyn Tool>> {
 127→        self.tools.get(tool_name).cloned()
 128→    }
 129→
 130→    pub fn definitions(&self) -> Vec<ToolDefinition> {
 131→        self.tools.values().map(|tool| tool.definition()).collect()
 132→    }
 133→}
