 636→    fn run_before_model(&self, request: &ProviderRequest) -> Result<(), CoreError> {
 637→        self.middlewares
 638→            .iter()
 639→            .try_for_each(|middleware| middleware.before_model_call(request))
 640→    }
 641→
 642→    fn run_after_model(
 643→        &self,
 644→        request: &ProviderRequest,
 645→        response: &ModelTurn,
 646→    ) -> Result<(), CoreError> {
 647→        self.middlewares
 648→            .iter()
 649→            .try_for_each(|middleware| middleware.after_model_call(request, response))
 650→    }
 651→
 652→    fn run_pre_tool(&self, context: &ToolContext, call: &ToolCall) -> Result<(), CoreError> {
 653→        self.middlewares
 654→            .iter()
 655→            .try_for_each(|middleware| middleware.pre_tool_call(context, call))
 656→    }
 657→
 658→    fn run_post_tool(&self, context: &ToolContext, result: &ToolResult) -> Result<(), CoreError> {
 659→        self.middlewares
 660→            .iter()
 661→            .try_for_each(|middleware| middleware.post_tool_call(context, result))
 662→    }
