  1→//! Advisory integration with the Autonomic homeostasis controller.
  2→//!
  3→//! [`AutonomicPolicyAdapter`] decorates an inner [`PolicyGatePort`] by consulting
  4→//! Autonomic's `/gating/{session_id}` HTTP endpoint before delegating. If Autonomic
  5→//! is unreachable or returns an error, the adapter fails open and delegates entirely
  6→//! to the inner gate (advisory semantics).
  7→//!
  8→//! Response types are duplicated locally to avoid coupling `arcan-aios-adapters`
  9→//! to `autonomic-core` at the crate level.
 10→
 11→use std::sync::Arc;
 12→
 13→use aios_protocol::{
 14→    Capability, GatingProfile, KernelError, PolicyGateDecision, PolicyGatePort, PolicySet,
 15→    SessionId,
 16→};
 17→use async_trait::async_trait;
 18→use serde::Deserialize;
 19→
 20→// ---------------------------------------------------------------------------
 21→// Public handle for economic gates (shared with provider layer in Phase 2)
 22→// ---------------------------------------------------------------------------
 23→
 24→/// Shared handle exposing the latest economic gates from Autonomic.
 25→///
 26→/// The provider layer can read this to adjust model selection and token budgets.
 27→pub type EconomicGateHandle = Arc<tokio::sync::RwLock<Option<EconomicGates>>>;
 28→
 29→// ---------------------------------------------------------------------------
 30→// Local response types (mirrors autonomic-core, avoids crate coupling)
 31→// ---------------------------------------------------------------------------
 32→
 33→/// HTTP response from `GET /gating/{session_id}`.
 34→#[derive(Debug, Deserialize)]
 35→struct GatingResponse {
 36→    #[allow(dead_code)]
 37→    session_id: String,
 38→    profile: LocalGatingProfile,
 39→    #[allow(dead_code)]
 40→    last_event_seq: u64,
 41→    #[allow(dead_code)]
 42→    last_event_ms: u64,
 43→}
 44→
 45→/// Mirrors `autonomic_core::gating::AutonomicGatingProfile`.
 46→#[derive(Debug, Clone, Deserialize)]
 47→struct LocalGatingProfile {
 48→    /// Canonical operational gates (from aios-protocol).
 49→    operational: GatingProfile,
 50→    /// Economic regulation gates.
 51→    economic: EconomicGates,
 52→    #[serde(default)]
 53→    #[allow(dead_code)]
 54→    rationale: Vec<String>,
 55→}
 56→
 57→/// Economic regulation gates from Autonomic.
 58→///
 59→/// Published so the provider layer can read model tier and token caps.
 60→#[derive(Debug, Clone, Deserialize)]
 61→pub struct EconomicGates {
 62→    /// Current economic operating mode.
 63→    pub economic_mode: EconomicMode,
 64→    /// Maximum tokens allowed for the next turn (advisory).
 65→    pub max_tokens_next_turn: Option<u32>,
 66→    /// Preferred model tier for cost control.
 67→    pub preferred_model: Option<ModelTier>,
 68→    /// Whether expensive tools (e.g., web search, code execution) are allowed.
 69→    pub allow_expensive_tools: bool,
 70→    /// Whether agent replication is allowed.
 71→    pub allow_replication: bool,
 72→}
 73→
 74→/// Economic operating mode, determined by balance-to-burn ratio.
 75→#[derive(Debug, Clone, Copy, PartialEq, Eq, Deserialize)]
 76→#[serde(rename_all = "snake_case")]
 77→pub enum EconomicMode {
 78→    Sovereign,
 79→    Conserving,
 80→    Hustle,
 81→    Hibernate,
 82→}
 83→
 84→/// LLM model tier for cost-aware selection.
 85→#[derive(Debug, Clone, Copy, PartialEq, Eq, Deserialize)]
 86→#[serde(rename_all = "snake_case")]
 87→pub enum ModelTier {
 88→    Flagship,
 89→    Standard,
 90→    Budget,
 91→}
 92→
 93→// ---------------------------------------------------------------------------
 94→// AutonomicPolicyAdapter
 95→// ---------------------------------------------------------------------------
 96→
 97→/// Decorator that optionally consults Autonomic before delegating to an inner
 98→/// [`PolicyGatePort`].
 99→///
100→/// Advisory semantics: if Autonomic is unreachable, the adapter falls through
101→/// to the inner gate. When Autonomic responds, the most-restrictive union of
102→/// Autonomic's operational gates and the inner decision wins.
103→pub struct AutonomicPolicyAdapter {
104→    inner: Arc<dyn PolicyGatePort>,
105→    client: reqwest::Client,
106→    base_url: String,
107→    economic_handle: EconomicGateHandle,
108→}
109→
110→impl AutonomicPolicyAdapter {
111→    /// Create a new adapter wrapping `inner`, consulting `base_url` for gating.
112→    pub fn new(inner: Arc<dyn PolicyGatePort>, base_url: String) -> Self {
113→        let client = reqwest::Client::builder()
114→            .timeout(std::time::Duration::from_secs(2))
115→            .build()
116→            .expect("failed to build reqwest client");
117→
118→        Self {
119→            inner,
120→            client,
121→            base_url,
122→            economic_handle: Arc::new(tokio::sync::RwLock::new(None)),
123→        }
124→    }
125→
126→    /// Returns a cloneable handle to the latest economic gates.
127→    pub fn economic_handle(&self) -> EconomicGateHandle {
128→        self.economic_handle.clone()
129→    }
130→}
131→
132→#[async_trait]
133→impl PolicyGatePort for AutonomicPolicyAdapter {
134→    async fn evaluate(
135→        &self,
136→        session_id: SessionId,
137→        requested: Vec<Capability>,
138→    ) -> Result<PolicyGateDecision, KernelError> {
139→        // 1. Get the inner (base) decision first.
140→        let inner_decision = self.inner.evaluate(session_id.clone(), requested).await?;
141→
142→        // 2. Consult Autonomic (advisory — errors fall through).
143→        let Some(gating) = self.fetch_gating(&session_id).await else {
