 177→            _ = sigterm.recv() => {},
 178→        }
 179→    }
 180→
 181→    #[cfg(not(unix))]
 182→    {
 183→        ctrl_c.await.ok();
 184→    }
 185→
 186→    tracing::info!("Received shutdown signal, draining connections...");
 187→}
