 198→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
 199→    let path = data_dir.join("last_session");
 200→    let raw = std::fs::read_to_string(path).ok()?;
 201→    let session = raw.trim();
 202→    if session.is_empty() {
 203→        None
 204→    } else {
 205→        Some(session.to_owned())
 206→    }
 207→}
