 319→fn run_serve(
 320→    data_dir: &Path,
 321→    resolved: &ResolvedConfig,
 322→    console_dir: Option<PathBuf>,
 323→) -> anyhow::Result<()> {
 324→    let workspace_root = std::env::current_dir()?;
 325→
 326→    // --- Lago persistence ---
 327→    let journal_path = data_dir.join("journal.redb");
 328→    let blobs_path = data_dir.join("blobs");
 329→    std::fs::create_dir_all(&blobs_path)?;
 330→
 331→    tracing::info!(
 332→        workspace = %workspace_root.display(),
 333→        journal = %journal_path.display(),
 334→        blobs = %blobs_path.display(),
 335→        provider = %resolved.provider,
 336→        model = ?resolved.model,
 337→        port = resolved.port,
 338→        "Starting arcan"
 339→    );
 340→
 341→    let journal = RedbJournal::open(&journal_path)?;
 342→    let blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 343→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 344→
 345→    // --- Lago-tracked filesystem (O(1) write tracking via FsTracker) ---
 346→    let fs_policy = FsPolicy::new(workspace_root.clone());
 347→    let local_fs = LocalFs::new(fs_policy);
 348→    let tracker = Arc::new(FsTracker::new(Manifest::new(), blob_store.clone()));
 349→    let (fs_event_tx, fs_event_rx) = tokio::sync::mpsc::channel(1000);
 350→    let tracked_fs: Arc<dyn FsPort> = Arc::new(LagoTrackedFs::new(local_fs, tracker, fs_event_tx));
 351→
 352→    let sandbox_policy = SandboxPolicy {
 353→        workspace_root: workspace_root.clone(),
 354→        shell_enabled: true,
 355→        network: NetworkPolicy::AllowAll,
 356→        allowed_env: BTreeSet::new(),
 357→        max_execution_ms: 10_000,
 358→        max_stdout_bytes: 1024 * 1024,
 359→        max_stderr_bytes: 1024 * 1024,
 360→    };
 361→
 362→    // --- Tools (Praxis canonical implementations, bridged into Arcan) ---
 363→    let mut registry = ToolRegistry::default();
 364→    registry.register(PraxisToolBridge::new(ReadFileTool::new(tracked_fs.clone())));
 365→    registry.register(PraxisToolBridge::new(WriteFileTool::new(
 366→        tracked_fs.clone(),
 367→    )));
 368→    registry.register(PraxisToolBridge::new(ListDirTool::new(tracked_fs.clone())));
 369→    registry.register(PraxisToolBridge::new(EditFileTool::new(tracked_fs.clone())));
 370→    registry.register(PraxisToolBridge::new(GlobTool::new(tracked_fs.clone())));
 371→    registry.register(PraxisToolBridge::new(GrepTool::new(tracked_fs)));
 372→
 373→    let runner = Box::new(LocalCommandRunner);
 374→    registry.register(PraxisToolBridge::new(BashTool::new(sandbox_policy, runner)));
 375→
 376→    let memory_dir = data_dir.join("memory");
 377→    std::fs::create_dir_all(&memory_dir)?;
 378→    registry.register(PraxisToolBridge::new(ReadMemoryTool::new(
 379→        memory_dir.clone(),
 380→    )));
 381→    registry.register(PraxisToolBridge::new(WriteMemoryTool::new(memory_dir)));
 382→
 383→    // --- Governed memory tools (event-sourced via Lago) ---
 384→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 385→    registry.register(MemoryQueryTool::new(memory_projection));
 386→    registry.register(MemoryProposeTool::new(journal.clone()));
 387→    registry.register(MemoryCommitTool::new(journal.clone()));
 388→
 389→    // --- Spaces distributed networking (opt-in) ---
 390→    #[cfg(feature = "spaces")]
 391→    {
 392→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> =
 393→            Arc::new(arcan_spaces::MockSpacesClient::default_hub());
 394→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 395→    }
 396→
 397→    // --- Provider ---
 398→    let provider = build_provider(resolved)?;
 399→
 400→    // Swappable handle for live provider switching
 401→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 402→        Arc::new(std::sync::RwLock::new(provider));
 403→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 404→        Arc::new(factory::ArcanProviderFactory);
 405→
 406→    // --- Canonical aiOS runtime adapters ---
 407→    let event_store: Arc<dyn EventStorePort> =
 408→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 409→    // Shared handle: starts empty, filled after runtime creation.
 410→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 411→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::from_handle(
 412→        provider_handle.clone(),
 413→        registry.definitions(),
 414→        streaming_sender.clone(),
 415→    ));
 416→    let tool_harness: Arc<dyn ToolHarnessPort> = Arc::new(ArcanHarnessAdapter::new(registry));
 417→    let base_policy: Arc<dyn PolicyGatePort> =
 418→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 419→
 420→    let (policy_gate, _economic_handle): (Arc<dyn PolicyGatePort>, Option<EconomicGateHandle>) =
 421→        if let Some(url) = &resolved.autonomic_url {
 422→            tracing::info!(url = %url, "Autonomic advisory enabled");
 423→            let adapter = AutonomicPolicyAdapter::new(base_policy, url.clone());
 424→            let handle = adapter.economic_handle();
 425→            (Arc::new(adapter), Some(handle))
 426→        } else {
 427→            (base_policy, None)
 428→        };
 429→
 430→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 431→
 432→    let runtime = Arc::new(KernelRuntime::new(
 433→        RuntimeConfig::new(data_dir.to_path_buf()),
 434→        event_store,
 435→        provider_adapter,
 436→        tool_harness,
 437→        approvals,
 438→        policy_gate,
 439→    ));
 440→
 441→    // Wire the broadcast sender now that the runtime exists.
 442→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 443→
 444→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 445→    let data_dir_owned = data_dir.to_path_buf();
 446→    let port = resolved.port;
 447→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 448→        .enable_all()
 449→        .build()?;
 450→
 451→    tokio_runtime.block_on(async move {
 452→        // --- Background FS event writer (persists tracked writes to Lago journal) ---
 453→        let session_id = SessionId::from_string("default");
 454→        let branch_id = BranchId::from_string("main");
 455→        tokio::spawn(run_event_writer(
 456→            fs_event_rx,
 457→            journal,
 458→            session_id,
 459→            branch_id,
 460→        ));
 461→
 462→        // --- HTTP Server ---
 463→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 464→
 465→        // --- Console UI ---
 466→        #[cfg(feature = "console")]
 467→        {
 468→            let console_config = arcan_console::ConsoleConfig {
 469→                override_dir: console_dir,
 470→            };
 471→            router = router.nest("/console", arcan_console::console_router(console_config));
 472→        }
 473→
 474→        // --- CORS (for dev mode with separate Vite server) ---
 475→        let cors = tower_http::cors::CorsLayer::permissive();
 476→        let router = router.layer(cors);
 477→
 478→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 479→        let listener = TcpListener::bind(addr).await?;
 480→
 481→        tracing::info!(%addr, "Listening");
 482→        axum::serve(listener, router)
 483→            .with_graceful_shutdown(shutdown_signal())
 484→            .await?;
 485→
 486→        // Clean up PID file on graceful shutdown.
 487→        daemon::remove_pid_file(&data_dir_owned);
 488→
 489→        tracing::info!("Server shut down gracefully");
 490→        Ok(())
 491→    })
 492→}
