 528→    message: String,
 529→    session: Option<String>,
 530→    url: Option<String>,
 531→    json_output: bool,
 532→) -> anyhow::Result<()> {
 533→    // Ensure daemon is running first.
 534→    let base_url = match url {
 535→        Some(u) => u,
 536→        None => {
 537→            daemon::ensure_daemon(
 538→                &data_dir,
 539→                resolved.port,
 540→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 541→                resolved.model.as_deref(),
 542→            )
 543→            .await?
 544→        }
 545→    };
 546→
 547→    // Resolve session via API (no direct journal access).
 548→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 549→
 550→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 551→        tracing::warn!(%error, "failed to persist last_session hint");
