 722→#[allow(clippy::print_stdout)]
 723→async fn run_api(
 724→    data_dir: PathBuf,
 725→    resolved: &ResolvedConfig,
 726→    url: Option<String>,
 727→    output: Option<PathBuf>,
 728→) -> anyhow::Result<()> {
 729→    // If --output is given, write the spec to a file and exit.
 730→    if let Some(path) = output {
 731→        let spec = arcand::canonical::openapi_spec();
 732→        let json = serde_json::to_string_pretty(&spec)?;
 733→        std::fs::write(&path, &json)?;
 734→        println!("OpenAPI spec written to {}", path.display());
 735→        return Ok(());
 736→    }
 737→
 738→    // Ensure daemon is running.
 739→    let base_url = match url {
 740→        Some(u) => u,
 741→        None => {
 742→            daemon::ensure_daemon(
 743→                &data_dir,
 744→                resolved.port,
 745→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 746→                resolved.model.as_deref(),
 747→            )
 748→            .await?
 749→        }
 750→    };
 751→
 752→    let docs_url = format!("{base_url}/docs");
 753→    println!("API docs available at: {docs_url}");
 754→
 755→    // Try to open the browser.
 756→    let opened = std::process::Command::new("open")
 757→        .arg(&docs_url)
 758→        .stdout(std::process::Stdio::null())
 759→        .stderr(std::process::Stdio::null())
 760→        .status()
 761→        .is_ok_and(|s| s.success());
 762→
 763→    if !opened {
 764→        println!("Open the URL above in your browser to explore the API.");
 765→    }
 766→
 767→    println!();
 768→    println!("Raw spec: {base_url}/openapi.json");
 769→
 770→    Ok(())
 771→}
