 58→        ArcanStopReason::EndTurn => ModelStopReason::Completed,
 59→        ArcanStopReason::ToolUse => ModelStopReason::ToolCall,
 60→        ArcanStopReason::NeedsUser => ModelStopReason::Cancelled,
 61→        ArcanStopReason::MaxTokens => ModelStopReason::MaxIterations,
 62→        ArcanStopReason::Safety => ModelStopReason::Error,
 63→        ArcanStopReason::Unknown => ModelStopReason::Other("unknown".to_owned()),
 64→    }
