 168→async fn shutdown_signal() {
 169→    let ctrl_c = tokio::signal::ctrl_c();
 170→
 171→    #[cfg(unix)]
 172→    {
 173→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
 174→            .expect("failed to install SIGTERM handler");
 175→        tokio::select! {
 176→            _ = ctrl_c => {},
 177→            _ = sigterm.recv() => {},
 178→        }
 179→    }
 180→
 181→    #[cfg(not(unix))]
 182→    {
 183→        ctrl_c.await.ok();
 184→    }
 185→
 186→    tracing::info!("Received shutdown signal, draining connections...");
 187→}
