 209→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
 210→    std::fs::create_dir_all(data_dir)?;
 211→    std::fs::write(data_dir.join("last_session"), session)?;
 212→    Ok(())
 213→}
