 569→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 570→    match action {
 571→        ConfigAction::Init => {
 572→            let path = config::local_config_path(data_dir);
 573→            if path.exists() {
 574→                println!("Config file already exists: {}", path.display());
 575→            } else {
 576→                std::fs::create_dir_all(data_dir)?;
 577→                std::fs::write(&path, config::default_config_content())?;
 578→                println!("Created config: {}", path.display());
 579→            }
 580→        }
 581→        ConfigAction::Set { key, value } => {
 582→            let mut cfg = config::load_config(data_dir);
 583→            cfg.set_key(&key, &value)
 584→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 585→            config::save_config(data_dir, &cfg)?;
 586→            println!("{key} = {value}");
 587→        }
 588→        ConfigAction::Get { key } => {
 589→            let cfg = config::load_config(data_dir);
 590→            match cfg.get_key(&key) {
 591→                Some(value) => println!("{value}"),
 592→                None => println!("(not set)"),
 593→            }
 594→        }
 595→        ConfigAction::List => {
 596→            let cfg = config::load_config(data_dir);
 597→            let content = toml::to_string_pretty(&cfg)
 598→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 599→            if content.trim().is_empty()
 600→                || content.trim() == "[defaults]\n\n[agent]"
 601→                || content
 602→                    .lines()
 603→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 604→            {
 605→                println!("(no config values set)");
 606→                if let Some(path) = config::global_config_path() {
 607→                    println!("Global config: {}", path.display());
 608→                }
 609→                println!(
 610→                    "Local config:  {}",
 611→                    config::local_config_path(data_dir).display()
 612→                );
 613→            } else {
 614→                print!("{content}");
 615→            }
 616→        }
 617→    }
 618→    Ok(())
 619→}
