 622→async fn run_status(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
 623→    println!("Arcan Status");
 624→    println!("============");
 625→
 626→    // Config
 627→    println!(
 628→        "Provider:   {}",
 629→        if resolved.provider.is_empty() {
 630→            "(auto-detect)"
 631→        } else {
 632→            &resolved.provider
 633→        }
 634→    );
 635→    println!(
 636→        "Model:      {}",
 637→        resolved.model.as_deref().unwrap_or("(provider default)")
 638→    );
 639→    println!("Port:       {}", resolved.port);
 640→    println!("Data dir:   {}", data_dir.display());
 641→
 642→    // Daemon status
 643→    let base_url = format!("http://127.0.0.1:{}", resolved.port);
 644→    match daemon::check_existing_pid(data_dir) {
 645→        Some(pid) => {
 646→            let client = reqwest::Client::builder()
 647→                .timeout(std::time::Duration::from_secs(2))
 648→                .build()?;
 649→            let healthy = matches!(
 650→                client.get(format!("{base_url}/health")).send().await,
 651→                Ok(resp) if resp.status().is_success()
 652→            );
 653→            if healthy {
 654→                println!("Daemon:     running (PID {pid}, healthy)");
 655→            } else {
 656→                println!("Daemon:     running (PID {pid}, NOT healthy)");
 657→            }
 658→        }
 659→        None => {
 660→            println!("Daemon:     not running");
 661→        }
 662→    }
 663→
 664→    // Last session
 665→    match read_last_session_hint(data_dir) {
 666→        Some(session) => println!("Session:    {session}"),
 667→        None => println!("Session:    (none)"),
 668→    }
 669→
 670→    // Config file locations
 671→    if let Some(global_path) = config::global_config_path() {
 672→        let exists = global_path.exists();
 673→        println!(
 674→            "Global cfg: {} {}",
 675→            global_path.display(),
 676→            if exists { "" } else { "(not found)" }
 677→        );
 678→    }
 679→    let local_path = config::local_config_path(data_dir);
 680→    let exists = local_path.exists();
 681→    println!(
 682→        "Local cfg:  {} {}",
 683→        local_path.display(),
 684→        if exists { "" } else { "(not found)" }
 685→    );
 686→
 687→    Ok(())
 688→}
