 794→fn main() -> anyhow::Result<()> {
 795→    let cli = Cli::parse();
 796→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 797→
 798→    // Load layered config.
 799→    let file_config = config::load_config(&data_dir);
 800→
 801→    match cli.command {
 802→        Some(Command::Serve {
 803→            max_iterations,
 804→            approval_timeout,
 805→        }) => {
 806→            // Structured logging to stderr for daemon mode
 807→            tracing_subscriber::fmt()
 808→                .with_env_filter(EnvFilter::from_default_env())
 809→                .init();
 810→
 811→            let resolved = config::resolve(
 812→                &file_config,
 813→                cli.provider.as_deref(),
 814→                cli.model.as_deref(),
 815→                cli.port,
 816→                max_iterations,
 817→                approval_timeout,
 818→                cli.autonomic_url.as_deref(),
 819→            );
 820→
 821→            run_serve(&data_dir, &resolved, cli.console_dir)
 822→        }
 823→        Some(Command::Chat { session, url }) => {
 824→            // File-based logging for TUI mode (don't clobber the terminal)
 825→            let log_dir = data_dir.join("logs");
 826→            std::fs::create_dir_all(&log_dir)?;
 827→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 828→            tracing_subscriber::fmt()
 829→                .with_writer(file_appender)
 830→                .with_env_filter(EnvFilter::from_default_env())
 831→                .init();
 832→
 833→            let resolved = config::resolve(
 834→                &file_config,
 835→                cli.provider.as_deref(),
 836→                cli.model.as_deref(),
 837→                cli.port,
 838→                None,
 839→                None,
 840→                cli.autonomic_url.as_deref(),
 841→            );
 842→
 843→            let runtime = tokio::runtime::Builder::new_multi_thread()
 844→                .enable_all()
 845→                .build()?;
 846→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
 847→        }
 848→        Some(Command::Login { provider, device }) => run_login(&provider, device, &data_dir),
 849→        Some(Command::Logout { provider }) => run_logout(&provider, &data_dir),
 850→        Some(Command::Api { url, output }) => {
 851→            let resolved = config::resolve(
 852→                &file_config,
 853→                cli.provider.as_deref(),
 854→                cli.model.as_deref(),
 855→                cli.port,
 856→                None,
 857→                None,
 858→                cli.autonomic_url.as_deref(),
 859→            );
 860→
 861→            let runtime = tokio::runtime::Builder::new_multi_thread()
 862→                .enable_all()
 863→                .build()?;
 864→            runtime.block_on(run_api(data_dir, &resolved, url, output))
 865→        }
 866→        Some(Command::Run {
 867→            message,
 868→            session,
 869→            url,
 870→            json,
 871→        }) => {
 872→            // File-based logging for CLI mode (don't clobber stdout)
 873→            let log_dir = data_dir.join("logs");
 874→            std::fs::create_dir_all(&log_dir)?;
 875→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
 876→            tracing_subscriber::fmt()
 877→                .with_writer(file_appender)
 878→                .with_env_filter(EnvFilter::from_default_env())
 879→                .init();
 880→
 881→            let resolved = config::resolve(
 882→                &file_config,
 883→                cli.provider.as_deref(),
 884→                cli.model.as_deref(),
 885→                cli.port,
 886→                None,
 887→                None,
 888→                cli.autonomic_url.as_deref(),
 889→            );
 890→
 891→            let runtime = tokio::runtime::Builder::new_multi_thread()
 892→                .enable_all()
 893→                .build()?;
 894→            runtime.block_on(run_message(
 895→                data_dir, &resolved, message, session, url, json,
 896→            ))
 897→        }
 898→        Some(Command::Config { action }) => run_config(&data_dir, action),
 899→        Some(Command::Status) => {
 900→            let resolved = config::resolve(
 901→                &file_config,
 902→                cli.provider.as_deref(),
 903→                cli.model.as_deref(),
 904→                cli.port,
 905→                None,
 906→                None,
 907→                cli.autonomic_url.as_deref(),
 908→            );
 909→
 910→            let runtime = tokio::runtime::Builder::new_multi_thread()
 911→                .enable_all()
 912→                .build()?;
 913→            runtime.block_on(run_status(&data_dir, &resolved))
 914→        }
 915→        Some(Command::Stop) => {
 916→            let resolved = config::resolve(
 917→                &file_config,
 918→                cli.provider.as_deref(),
 919→                cli.model.as_deref(),
 920→                cli.port,
 921→                None,
 922→                None,
 923→                cli.autonomic_url.as_deref(),
 924→            );
 925→
 926→            let runtime = tokio::runtime::Builder::new_multi_thread()
 927→                .enable_all()
 928→                .build()?;
 929→            runtime.block_on(daemon::stop_daemon(&data_dir, resolved.port))
 930→        }
 931→        None => {
 932→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
 933→            let log_dir = data_dir.join("logs");
 934→            std::fs::create_dir_all(&log_dir)?;
 935→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 936→            tracing_subscriber::fmt()
 937→                .with_writer(file_appender)
 938→                .with_env_filter(EnvFilter::from_default_env())
 939→                .init();
 940→
 941→            let resolved = config::resolve(
 942→                &file_config,
 943→                cli.provider.as_deref(),
 944→                cli.model.as_deref(),
 945→                cli.port,
 946→                None,
 947→                None,
 948→                cli.autonomic_url.as_deref(),
 949→            );
 950→
 951→            let runtime = tokio::runtime::Builder::new_multi_thread()
 952→                .enable_all()
 953→                .build()?;
 954→            runtime.block_on(run_chat(data_dir, &resolved, None, None))
 955→        }
 956→    }
 957→}
