 243→    let credential = Arc::new(arcan_provider::oauth::OAuthCredential::openai(tokens));
 244→    let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
 245→    let config = arcan_provider::openai::OpenAiConfig::from_oauth(credential, model.clone());
 246→    tracing::info!(%model, "Provider: OpenAI (OAuth)");
 247→    Some(Arc::new(
 248→        arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 249→    ))
 250→}
