 319→fn run_serve(
 320→    data_dir: &Path,
 321→    resolved: &ResolvedConfig,
 322→    console_dir: Option<PathBuf>,
 323→) -> anyhow::Result<()> {
 324→    let workspace_root = std::env::current_dir()?;
 325→
 326→    // --- Lago persistence ---
 327→    let journal_path = data_dir.join("journal.redb");
 328→    let blobs_path = data_dir.join("blobs");
 329→    std::fs::create_dir_all(&blobs_path)?;
 330→
 331→    tracing::info!(
 332→        workspace = %workspace_root.display(),
 333→        journal = %journal_path.display(),
 334→        blobs = %blobs_path.display(),
 335→        provider = %resolved.provider,
 336→        model = ?resolved.model,
 337→        port = resolved.port,
 338→        "Starting arcan"
 339→    );
 340→
 341→    let journal = RedbJournal::open(&journal_path)?;
 342→    let blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 343→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 344→
 345→    // --- Lago-tracked filesystem (O(1) write tracking via FsTracker) ---
 346→    let fs_policy = FsPolicy::new(workspace_root.clone());
 347→    let local_fs = LocalFs::new(fs_policy);
 348→    let tracker = Arc::new(FsTracker::new(Manifest::new(), blob_store.clone()));
 349→    let (fs_event_tx, fs_event_rx) = tokio::sync::mpsc::channel(1000);
 350→    let tracked_fs: Arc<dyn FsPort> = Arc::new(LagoTrackedFs::new(local_fs, tracker, fs_event_tx));
 351→
 352→    let sandbox_policy = SandboxPolicy {
 353→        workspace_root: workspace_root.clone(),
 354→        shell_enabled: true,
 355→        network: NetworkPolicy::AllowAll,
 356→        allowed_env: BTreeSet::new(),
 357→        max_execution_ms: 10_000,
 358→        max_stdout_bytes: 1024 * 1024,
 359→        max_stderr_bytes: 1024 * 1024,
 360→    };
 361→
 362→    // --- Tools (Praxis canonical implementations, bridged into Arcan) ---
 363→    let mut registry = ToolRegistry::default();
 364→    registry.register(PraxisToolBridge::new(ReadFileTool::new(tracked_fs.clone())));
 365→    registry.register(PraxisToolBridge::new(WriteFileTool::new(
 366→        tracked_fs.clone(),
 367→    )));
 368→    registry.register(PraxisToolBridge::new(ListDirTool::new(tracked_fs.clone())));
 369→    registry.register(PraxisToolBridge::new(EditFileTool::new(tracked_fs.clone())));
 370→    registry.register(PraxisToolBridge::new(GlobTool::new(tracked_fs.clone())));
 371→    registry.register(PraxisToolBridge::new(GrepTool::new(tracked_fs)));
 372→
 373→    let runner = Box::new(LocalCommandRunner);
 374→    registry.register(PraxisToolBridge::new(BashTool::new(sandbox_policy, runner)));
 375→
 376→    let memory_dir = data_dir.join("memory");
 377→    std::fs::create_dir_all(&memory_dir)?;
 378→    registry.register(PraxisToolBridge::new(ReadMemoryTool::new(
 379→        memory_dir.clone(),
 380→    )));
 381→    registry.register(PraxisToolBridge::new(WriteMemoryTool::new(memory_dir)));
 382→
 383→    // --- Governed memory tools (event-sourced via Lago) ---
 384→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 385→    registry.register(MemoryQueryTool::new(memory_projection));
 386→    registry.register(MemoryProposeTool::new(journal.clone()));
 387→    registry.register(MemoryCommitTool::new(journal.clone()));
 388→
 389→    // --- Spaces distributed networking (opt-in) ---
 390→    #[cfg(feature = "spaces")]
 391→    {
 392→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> =
 393→            Arc::new(arcan_spaces::MockSpacesClient::default_hub());
 394→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 395→    }
 396→
 397→    // --- Provider ---
 398→    let provider = build_provider(resolved)?;
 399→
 400→    // Swappable handle for live provider switching
 401→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 402→        Arc::new(std::sync::RwLock::new(provider));
 403→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 404→        Arc::new(factory::ArcanProviderFactory);
 405→
 406→    // --- Canonical aiOS runtime adapters ---
 407→    let event_store: Arc<dyn EventStorePort> =
 408→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 409→    let base_policy: Arc<dyn PolicyGatePort> =
 410→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 411→
 412→    // --- Autonomic advisory gate (embedded by default, remote via --autonomic-url) ---
 413→    let (policy_gate, economic_handle): (Arc<dyn PolicyGatePort>, EconomicGateHandle) =
 414→        if let Some(url) = &resolved.autonomic_url {
 415→            // Remote: consult standalone Autonomic daemon via HTTP.
 416→            tracing::info!(url = %url, "Autonomic advisory enabled (remote)");
 417→            let adapter = AutonomicPolicyAdapter::new_remote(base_policy, url.clone());
 418→            let handle = adapter.economic_handle();
 419→            (Arc::new(adapter), handle)
 420→        } else {
 421→            // Embedded: run controller in-process (default).
 422→            tracing::info!("Autonomic advisory enabled (embedded)");
 423→            let adapter = AutonomicPolicyAdapter::new_embedded(base_policy);
 424→            let handle = adapter.economic_handle();
 425→            (Arc::new(adapter), handle)
 426→        };
 427→
 428→    // --- Provider adapter (wired with economic handle for cost gating) ---
 429→    // Shared handle: starts empty, filled after runtime creation.
 430→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 431→    let tool_definitions = registry.definitions();
 432→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(
 433→        ArcanProviderAdapter::from_handle(
 434→            provider_handle.clone(),
 435→            tool_definitions,
 436→            streaming_sender.clone(),
 437→        )
 438→        .with_economic_handle(economic_handle),
 439→    );
 440→    let tool_harness: Arc<dyn ToolHarnessPort> = Arc::new(ArcanHarnessAdapter::new(registry));
 441→
 442→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 443→
 444→    let runtime = Arc::new(KernelRuntime::new(
 445→        RuntimeConfig::new(data_dir.to_path_buf()),
 446→        event_store,
 447→        provider_adapter,
 448→        tool_harness,
 449→        approvals,
 450→        policy_gate,
 451→    ));
 452→
 453→    // Wire the broadcast sender now that the runtime exists.
 454→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 455→
 456→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 457→    let data_dir_owned = data_dir.to_path_buf();
 458→    let port = resolved.port;
 459→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 460→        .enable_all()
 461→        .build()?;
 462→
 463→    tokio_runtime.block_on(async move {
 464→        // --- Background FS event writer (persists tracked writes to Lago journal) ---
 465→        let session_id = SessionId::from_string("default");
 466→        let branch_id = BranchId::from_string("main");
 467→        tokio::spawn(run_event_writer(
 468→            fs_event_rx,
 469→            journal,
 470→            session_id,
 471→            branch_id,
 472→        ));
 473→
 474→        // --- HTTP Server ---
 475→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 476→
 477→        // --- Console UI ---
 478→        #[cfg(feature = "console")]
 479→        {
 480→            let console_config = arcan_console::ConsoleConfig {
 481→                override_dir: console_dir,
 482→            };
 483→            router = router.nest("/console", arcan_console::console_router(console_config));
 484→        }
 485→
 486→        // --- CORS (for dev mode with separate Vite server) ---
 487→        let cors = tower_http::cors::CorsLayer::permissive();
 488→        let router = router.layer(cors);
 489→
 490→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 491→        let listener = TcpListener::bind(addr).await?;
 492→
 493→        tracing::info!(%addr, "Listening");
 494→        axum::serve(listener, router)
 495→            .with_graceful_shutdown(shutdown_signal())
 496→            .await?;
 497→
 498→        // Clean up PID file on graceful shutdown.
 499→        daemon::remove_pid_file(&data_dir_owned);
 500→
 501→        tracing::info!("Server shut down gracefully");
 502→        Ok(())
 503→    })
 504→}
