 506→async fn run_chat(
 507→    data_dir: PathBuf,
 508→    resolved: &ResolvedConfig,
 509→    session: Option<String>,
 510→    url: Option<String>,
 511→) -> anyhow::Result<()> {
 512→    // Ensure daemon is running first to avoid redb lock conflicts.
 513→    let base_url = match url {
 514→        Some(u) => u,
 515→        None => {
 516→            daemon::ensure_daemon(
 517→                &data_dir,
 518→                resolved.port,
 519→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 520→                resolved.model.as_deref(),
 521→            )
 522→            .await?
 523→        }
 524→    };
 525→
 526→    // Resolve session via API (no direct journal access).
 527→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 528→    tracing::info!(session = %session, "launching TUI");
 529→
 530→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 531→        tracing::warn!(%error, "failed to persist last_session hint");
 532→    }
 533→
 534→    arcan_tui::run_tui(base_url, session).await
 535→}
