 581→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 582→    match action {
 583→        ConfigAction::Init => {
 584→            let path = config::local_config_path(data_dir);
 585→            if path.exists() {
 586→                println!("Config file already exists: {}", path.display());
 587→            } else {
 588→                std::fs::create_dir_all(data_dir)?;
 589→                std::fs::write(&path, config::default_config_content())?;
 590→                println!("Created config: {}", path.display());
 591→            }
 592→        }
 593→        ConfigAction::Set { key, value } => {
 594→            let mut cfg = config::load_config(data_dir);
 595→            cfg.set_key(&key, &value)
 596→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 597→            config::save_config(data_dir, &cfg)?;
 598→            println!("{key} = {value}");
 599→        }
 600→        ConfigAction::Get { key } => {
 601→            let cfg = config::load_config(data_dir);
 602→            match cfg.get_key(&key) {
 603→                Some(value) => println!("{value}"),
 604→                None => println!("(not set)"),
 605→            }
 606→        }
 607→        ConfigAction::List => {
 608→            let cfg = config::load_config(data_dir);
 609→            let content = toml::to_string_pretty(&cfg)
 610→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 611→            if content.trim().is_empty()
 612→                || content.trim() == "[defaults]\n\n[agent]"
 613→                || content
 614→                    .lines()
 615→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 616→            {
 617→                println!("(no config values set)");
 618→                if let Some(path) = config::global_config_path() {
 619→                    println!("Global config: {}", path.display());
 620→                }
 621→                println!(
 622→                    "Local config:  {}",
 623→                    config::local_config_path(data_dir).display()
 624→                );
 625→            } else {
 626→                print!("{content}");
 627→            }
 628→        }
 629→    }
 630→    Ok(())
 631→}
