 703→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 704→    // Normalize to canonical provider name for config persistence.
 705→    let canonical = match provider {
 706→        "codex" | "openai-codex" => "openai",
 707→        other => other,
 708→    };
 709→
 710→    match provider {
 711→        "openai" | "codex" | "openai-codex" => {
 712→            if device {
 713→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 714→            } else {
 715→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 716→            }
 717→        }
 718→        _ => {
 719→            return Err(anyhow::anyhow!(
 720→                "Unknown provider '{provider}'. Supported: openai"
 721→            ));
 722→        }
 723→    }
 724→
 725→    // Set the provider as the new default after successful login.
 726→    let mut file_config = config::load_config(data_dir);
 727→    file_config.set_key("provider", canonical).ok();
 728→    config::save_config(data_dir, &file_config)?;
 729→    eprintln!("Default provider set to '{canonical}'");
 730→
 731→    Ok(())
 732→}
