 786→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 787→    // Normalize provider name for credential lookup.
 788→    let normalized = match provider {
 789→        "codex" | "openai-codex" => "openai",
 790→        other => other,
 791→    };
 792→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 793→
 794→    // Clear the default provider if it matches the one being logged out.
 795→    let mut file_config = config::load_config(data_dir);
 796→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 797→        file_config.defaults.provider = None;
 798→        config::save_config(data_dir, &file_config)?;
 799→        eprintln!("Default provider cleared");
 800→    }
 801→
 802→    eprintln!("Logged out of {provider}");
 803→    Ok(())
 804→}
