 806→fn main() -> anyhow::Result<()> {
 807→    let cli = Cli::parse();
 808→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 809→
 810→    // Load layered config.
 811→    let file_config = config::load_config(&data_dir);
 812→
 813→    match cli.command {
 814→        Some(Command::Serve {
 815→            max_iterations,
 816→            approval_timeout,
 817→        }) => {
 818→            // Structured logging to stderr for daemon mode
 819→            tracing_subscriber::fmt()
 820→                .with_env_filter(EnvFilter::from_default_env())
