 223→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 224→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 225→async fn resolve_session(
 226→    data_dir: &Path,
 227→    requested: Option<String>,
 228→    base_url: Option<&str>,
 229→) -> String {
 230→    if let Some(session) = requested {
 231→        return session;
 232→    }
 233→
 234→    if let Some(session) = read_last_session_hint(data_dir) {
 235→        return session;
 236→    }
 237→
 238→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 239→    if let Some(url) = base_url {
 240→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 241→            return session;
 242→        }
 243→    }
 244→
 245→    "default".to_owned()
 246→}
