 288→                pc.and_then(|p| p.max_tokens),
 289→                pc.and_then(|p| p.enable_streaming),
 290→            )?;
 291→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 292→            Ok(Arc::new(
 293→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 294→            ))
 295→        }
 296→        "anthropic" => {
 297→            let config = AnthropicConfig::from_resolved(
 298→                resolved.model.as_deref(),
 299→                pc.and_then(|p| p.base_url.as_deref()),
 300→                pc.and_then(|p| p.max_tokens),
 301→            )?;
 302→            tracing::info!(model = %config.model, "Provider: Anthropic");
 303→            Ok(Arc::new(AnthropicProvider::new(config)))
 304→        }
 305→        // Auto-detect: try providers in order
 306→        _ => {
 307→            if let Ok(config) = AnthropicConfig::from_env() {
 308→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 309→                Ok(Arc::new(AnthropicProvider::new(config)))
 310→            } else if let Some(p) = try_openai_oauth_provider() {
