 327→fn run_serve(
 328→    data_dir: &Path,
 329→    resolved: &ResolvedConfig,
 330→    console_dir: Option<PathBuf>,
 331→) -> anyhow::Result<()> {
 332→    let workspace_root = std::env::current_dir()?;
 333→
 334→    // --- Lago persistence ---
 335→    let journal_path = data_dir.join("journal.redb");
 336→    let blobs_path = data_dir.join("blobs");
 337→    std::fs::create_dir_all(&blobs_path)?;
 338→
 339→    tracing::info!(
 340→        workspace = %workspace_root.display(),
 341→        journal = %journal_path.display(),
 342→        blobs = %blobs_path.display(),
 343→        provider = %resolved.provider,
 344→        model = ?resolved.model,
 345→        port = resolved.port,
 346→        "Starting arcan"
 347→    );
 348→
 349→    let journal = RedbJournal::open(&journal_path)?;
 350→    let blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 351→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 352→
 353→    // --- Lago-tracked filesystem (O(1) write tracking via FsTracker) ---
 354→    let fs_policy = FsPolicy::new(workspace_root.clone());
 355→    let local_fs = LocalFs::new(fs_policy);
 356→    let tracker = Arc::new(FsTracker::new(Manifest::new(), blob_store.clone()));
 357→    let (fs_event_tx, fs_event_rx) = tokio::sync::mpsc::channel(1000);
 358→    let tracked_fs: Arc<dyn FsPort> = Arc::new(LagoTrackedFs::new(local_fs, tracker, fs_event_tx));
 359→
 360→    let sandbox_policy = SandboxPolicy {
 361→        workspace_root: workspace_root.clone(),
 362→        shell_enabled: true,
 363→        network: NetworkPolicy::AllowAll,
 364→        allowed_env: BTreeSet::new(),
 365→        max_execution_ms: 10_000,
 366→        max_stdout_bytes: 1024 * 1024,
 367→        max_stderr_bytes: 1024 * 1024,
 368→    };
 369→
 370→    // --- Tools (Praxis canonical implementations, bridged into Arcan) ---
 371→    let mut registry = ToolRegistry::default();
 372→    registry.register(PraxisToolBridge::new(ReadFileTool::new(tracked_fs.clone())));
 373→    registry.register(PraxisToolBridge::new(WriteFileTool::new(
 374→        tracked_fs.clone(),
 375→    )));
 376→    registry.register(PraxisToolBridge::new(ListDirTool::new(tracked_fs.clone())));
 377→    registry.register(PraxisToolBridge::new(EditFileTool::new(tracked_fs.clone())));
 378→    registry.register(PraxisToolBridge::new(GlobTool::new(tracked_fs.clone())));
 379→    registry.register(PraxisToolBridge::new(GrepTool::new(tracked_fs)));
 380→
 381→    let runner = Box::new(LocalCommandRunner);
 382→    registry.register(PraxisToolBridge::new(BashTool::new(sandbox_policy, runner)));
 383→
 384→    let memory_dir = data_dir.join("memory");
 385→    std::fs::create_dir_all(&memory_dir)?;
 386→    registry.register(PraxisToolBridge::new(ReadMemoryTool::new(
 387→        memory_dir.clone(),
 388→    )));
 389→    registry.register(PraxisToolBridge::new(WriteMemoryTool::new(memory_dir)));
 390→
 391→    // --- Governed memory tools (event-sourced via Lago) ---
 392→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 393→    registry.register(MemoryQueryTool::new(memory_projection));
 394→    registry.register(MemoryProposeTool::new(journal.clone()));
 395→    registry.register(MemoryCommitTool::new(journal.clone()));
 396→
 397→    // --- Spaces distributed networking (opt-in) ---
 398→    #[cfg(feature = "spaces")]
 399→    {
 400→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> =
 401→            Arc::new(arcan_spaces::MockSpacesClient::default_hub());
 402→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 403→    }
 404→
 405→    // --- Provider ---
 406→    let provider = build_provider(resolved)?;
 407→
 408→    // Swappable handle for live provider switching
 409→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 410→        Arc::new(std::sync::RwLock::new(provider));
 411→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 412→        Arc::new(factory::ArcanProviderFactory);
 413→
 414→    // --- Canonical aiOS runtime adapters ---
 415→    let event_store: Arc<dyn EventStorePort> =
 416→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 417→    let base_policy: Arc<dyn PolicyGatePort> =
 418→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 419→
 420→    // --- Autonomic advisory gate (embedded by default, remote via --autonomic-url) ---
 421→    let (policy_gate, economic_handle): (Arc<dyn PolicyGatePort>, EconomicGateHandle) =
 422→        if let Some(url) = &resolved.autonomic_url {
 423→            // Remote: consult standalone Autonomic daemon via HTTP.
 424→            tracing::info!(url = %url, "Autonomic advisory enabled (remote)");
 425→            let adapter = AutonomicPolicyAdapter::new_remote(base_policy, url.clone());
 426→            let handle = adapter.economic_handle();
 427→            (Arc::new(adapter), handle)
 428→        } else {
 429→            // Embedded: run controller in-process (default).
 430→            tracing::info!("Autonomic advisory enabled (embedded)");
 431→            let adapter = AutonomicPolicyAdapter::new_embedded(base_policy);
 432→            let handle = adapter.economic_handle();
 433→            (Arc::new(adapter), handle)
 434→        };
 435→
 436→    // --- Provider adapter (wired with economic handle for cost gating) ---
 437→    // Shared handle: starts empty, filled after runtime creation.
 438→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 439→    let tool_definitions = registry.definitions();
 440→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(
 441→        ArcanProviderAdapter::from_handle(
 442→            provider_handle.clone(),
 443→            tool_definitions,
 444→            streaming_sender.clone(),
 445→        )
 446→        .with_economic_handle(economic_handle),
 447→    );
 448→    let tool_harness: Arc<dyn ToolHarnessPort> = Arc::new(ArcanHarnessAdapter::new(registry));
 449→
 450→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 451→
 452→    let runtime = Arc::new(KernelRuntime::new(
 453→        RuntimeConfig::new(data_dir.to_path_buf()),
 454→        event_store,
 455→        provider_adapter,
 456→        tool_harness,
 457→        approvals,
 458→        policy_gate,
 459→    ));
 460→
 461→    // Wire the broadcast sender now that the runtime exists.
 462→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 463→
 464→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 465→    let data_dir_owned = data_dir.to_path_buf();
 466→    let port = resolved.port;
 467→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 468→        .enable_all()
 469→        .build()?;
 470→
 471→    tokio_runtime.block_on(async move {
 472→        // --- Background FS event writer (persists tracked writes to Lago journal) ---
 473→        let session_id = SessionId::from_string("default");
 474→        let branch_id = BranchId::from_string("main");
 475→        tokio::spawn(run_event_writer(
 476→            fs_event_rx,
 477→            journal,
 478→            session_id,
 479→            branch_id,
 480→        ));
 481→
 482→        // --- HTTP Server ---
 483→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 484→
 485→        // --- Console UI ---
 486→        #[cfg(feature = "console")]
 487→        {
 488→            let console_config = arcan_console::ConsoleConfig {
 489→                override_dir: console_dir,
 490→            };
 491→            router = router.nest("/console", arcan_console::console_router(console_config));
 492→        }
 493→
 494→        // --- CORS (for dev mode with separate Vite server) ---
 495→        let cors = tower_http::cors::CorsLayer::permissive();
 496→        let router = router.layer(cors);
 497→
 498→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 499→        let listener = TcpListener::bind(addr).await?;
 500→
 501→        tracing::info!(%addr, "Listening");
 502→        axum::serve(listener, router)
 503→            .with_graceful_shutdown(shutdown_signal())
 504→            .await?;
 505→
 506→        // Clean up PID file on graceful shutdown.
 507→        daemon::remove_pid_file(&data_dir_owned);
 508→
 509→        tracing::info!("Server shut down gracefully");
 510→        Ok(())
 511→    })
 512→}
