 514→async fn run_chat(
 515→    data_dir: PathBuf,
 516→    resolved: &ResolvedConfig,
 517→    session: Option<String>,
 518→    url: Option<String>,
 519→) -> anyhow::Result<()> {
 520→    // Ensure daemon is running first to avoid redb lock conflicts.
 521→    let base_url = match url {
 522→        Some(u) => u,
 523→        None => {
 524→            daemon::ensure_daemon(
 525→                &data_dir,
 526→                resolved.port,
 527→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 528→                resolved.model.as_deref(),
 529→            )
 530→            .await?
 531→        }
 532→    };
 533→
 534→    // Resolve session via API (no direct journal access).
 535→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 536→    tracing::info!(session = %session, "launching TUI");
 537→
 538→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 539→        tracing::warn!(%error, "failed to persist last_session hint");
 540→    }
 541→
 542→    arcan_tui::run_tui(base_url, session).await
 543→}
