 545→async fn run_message(
 546→    data_dir: PathBuf,
 547→    resolved: &ResolvedConfig,
 548→    message: String,
 549→    session: Option<String>,
 550→    url: Option<String>,
 551→    json_output: bool,
 552→) -> anyhow::Result<()> {
 553→    // Ensure daemon is running first.
 554→    let base_url = match url {
 555→        Some(u) => u,
 556→        None => {
 557→            daemon::ensure_daemon(
 558→                &data_dir,
 559→                resolved.port,
 560→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 561→                resolved.model.as_deref(),
 562→            )
 563→            .await?
 564→        }
 565→    };
 566→
 567→    // Resolve session via API (no direct journal access).
 568→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 569→
 570→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 571→        tracing::warn!(%error, "failed to persist last_session hint");
 572→    }
 573→
 574→    let exit_code = cli_run::run_cli(
 575→        &base_url,
 576→        &session,
 577→        &message,
 578→        json_output,
 579→        resolved.model.as_deref(),
