 589→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 590→    match action {
 591→        ConfigAction::Init => {
 592→            let path = config::local_config_path(data_dir);
 593→            if path.exists() {
 594→                println!("Config file already exists: {}", path.display());
 595→            } else {
 596→                std::fs::create_dir_all(data_dir)?;
 597→                std::fs::write(&path, config::default_config_content())?;
 598→                println!("Created config: {}", path.display());
 599→            }
 600→        }
 601→        ConfigAction::Set { key, value } => {
 602→            let mut cfg = config::load_config(data_dir);
 603→            cfg.set_key(&key, &value)
 604→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 605→            config::save_config(data_dir, &cfg)?;
 606→            println!("{key} = {value}");
 607→        }
 608→        ConfigAction::Get { key } => {
 609→            let cfg = config::load_config(data_dir);
 610→            match cfg.get_key(&key) {
 611→                Some(value) => println!("{value}"),
 612→                None => println!("(not set)"),
 613→            }
 614→        }
 615→        ConfigAction::List => {
 616→            let cfg = config::load_config(data_dir);
 617→            let content = toml::to_string_pretty(&cfg)
 618→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 619→            if content.trim().is_empty()
 620→                || content.trim() == "[defaults]\n\n[agent]"
 621→                || content
 622→                    .lines()
 623→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 624→            {
 625→                println!("(no config values set)");
 626→                if let Some(path) = config::global_config_path() {
 627→                    println!("Global config: {}", path.display());
 628→                }
 629→                println!(
 630→                    "Local config:  {}",
 631→                    config::local_config_path(data_dir).display()
 632→                );
 633→            } else {
 634→                print!("{content}");
 635→            }
 636→        }
 637→    }
 638→    Ok(())
 639→}
