 642→async fn run_status(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
 643→    println!("Arcan Status");
 644→    println!("============");
 645→
 646→    // Config
 647→    println!(
 648→        "Provider:   {}",
 649→        if resolved.provider.is_empty() {
 650→            "(auto-detect)"
 651→        } else {
 652→            &resolved.provider
 653→        }
 654→    );
 655→    println!(
 656→        "Model:      {}",
 657→        resolved.model.as_deref().unwrap_or("(provider default)")
 658→    );
 659→    println!("Port:       {}", resolved.port);
 660→    println!("Data dir:   {}", data_dir.display());
 661→
 662→    // Daemon status
 663→    let base_url = format!("http://127.0.0.1:{}", resolved.port);
 664→    match daemon::check_existing_pid(data_dir) {
 665→        Some(pid) => {
 666→            let client = reqwest::Client::builder()
 667→                .timeout(std::time::Duration::from_secs(2))
 668→                .build()?;
 669→            let healthy = matches!(
 670→                client.get(format!("{base_url}/health")).send().await,
 671→                Ok(resp) if resp.status().is_success()
 672→            );
 673→            if healthy {
 674→                println!("Daemon:     running (PID {pid}, healthy)");
 675→            } else {
 676→                println!("Daemon:     running (PID {pid}, NOT healthy)");
 677→            }
 678→        }
 679→        None => {
 680→            println!("Daemon:     not running");
 681→        }
 682→    }
 683→
 684→    // Last session
 685→    match read_last_session_hint(data_dir) {
 686→        Some(session) => println!("Session:    {session}"),
 687→        None => println!("Session:    (none)"),
 688→    }
 689→
 690→    // Config file locations
 691→    if let Some(global_path) = config::global_config_path() {
 692→        let exists = global_path.exists();
 693→        println!(
 694→            "Global cfg: {} {}",
 695→            global_path.display(),
 696→            if exists { "" } else { "(not found)" }
 697→        );
 698→    }
 699→    let local_path = config::local_config_path(data_dir);
 700→    let exists = local_path.exists();
 701→    println!(
 702→        "Local cfg:  {} {}",
 703→        local_path.display(),
 704→        if exists { "" } else { "(not found)" }
 705→    );
 706→
 707→    Ok(())
 708→}
