 710→#[allow(clippy::print_stderr)]
 711→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 712→    // Normalize to canonical provider name for config persistence.
 713→    let canonical = match provider {
 714→        "codex" | "openai-codex" => "openai",
 715→        other => other,
 716→    };
 717→
 718→    match provider {
 719→        "openai" | "codex" | "openai-codex" => {
 720→            if device {
 721→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 722→            } else {
 723→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 724→            }
 725→        }
 726→        _ => {
 727→            return Err(anyhow::anyhow!(
 728→                "Unknown provider '{provider}'. Supported: openai"
 729→            ));
 730→        }
 731→    }
 732→
 733→    // Set the provider as the new default after successful login.
 734→    let mut file_config = config::load_config(data_dir);
 735→    file_config.set_key("provider", canonical).ok();
 736→    config::save_config(data_dir, &file_config)?;
 737→    eprintln!("Default provider set to '{canonical}'");
 738→
 739→    Ok(())
 740→}
