 742→#[allow(clippy::print_stdout)]
 743→async fn run_api(
 744→    data_dir: PathBuf,
 745→    resolved: &ResolvedConfig,
 746→    url: Option<String>,
 747→    output: Option<PathBuf>,
 748→) -> anyhow::Result<()> {
 749→    // If --output is given, write the spec to a file and exit.
 750→    if let Some(path) = output {
 751→        let spec = arcand::canonical::openapi_spec();
 752→        let json = serde_json::to_string_pretty(&spec)?;
 753→        std::fs::write(&path, &json)?;
 754→        println!("OpenAPI spec written to {}", path.display());
 755→        return Ok(());
 756→    }
 757→
 758→    // Ensure daemon is running.
 759→    let base_url = match url {
 760→        Some(u) => u,
 761→        None => {
 762→            daemon::ensure_daemon(
 763→                &data_dir,
 764→                resolved.port,
 765→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 766→                resolved.model.as_deref(),
 767→            )
 768→            .await?
 769→        }
 770→    };
 771→
 772→    let docs_url = format!("{base_url}/docs");
 773→    println!("API docs available at: {docs_url}");
 774→
 775→    // Try to open the browser.
 776→    let opened = std::process::Command::new("open")
 777→        .arg(&docs_url)
 778→        .stdout(std::process::Stdio::null())
 779→        .stderr(std::process::Stdio::null())
 780→        .status()
 781→        .is_ok_and(|s| s.success());
 782→
 783→    if !opened {
 784→        println!("Open the URL above in your browser to explore the API.");
 785→    }
 786→
 787→    println!();
 788→    println!("Raw spec: {base_url}/openapi.json");
 789→
 790→    Ok(())
 791→}
