 793→#[allow(clippy::print_stderr)]
 794→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 795→    // Normalize provider name for credential lookup.
 796→    let normalized = match provider {
 797→        "codex" | "openai-codex" => "openai",
 798→        other => other,
 799→    };
 800→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 801→
 802→    // Clear the default provider if it matches the one being logged out.
 803→    let mut file_config = config::load_config(data_dir);
 804→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 805→        file_config.defaults.provider = None;
 806→        config::save_config(data_dir, &file_config)?;
 807→        eprintln!("Default provider cleared");
 808→    }
 809→
 810→    eprintln!("Logged out of {provider}");
 811→    Ok(())
 812→}
