 814→fn main() -> anyhow::Result<()> {
 815→    let cli = Cli::parse();
 816→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 817→
 818→    // Load layered config.
 819→    let file_config = config::load_config(&data_dir);
 820→
 821→    match cli.command {
 822→        Some(Command::Serve {
 823→            max_iterations,
 824→            approval_timeout,
 825→        }) => {
 826→            // Structured logging to stderr for daemon mode
 827→            tracing_subscriber::fmt()
 828→                .with_env_filter(EnvFilter::from_default_env())
 829→                .init();
 830→
 831→            let resolved = config::resolve(
 832→                &file_config,
 833→                cli.provider.as_deref(),
 834→                cli.model.as_deref(),
 835→                cli.port,
 836→                max_iterations,
 837→                approval_timeout,
 838→                cli.autonomic_url.as_deref(),
 839→            );
 840→
 841→            run_serve(&data_dir, &resolved, cli.console_dir)
 842→        }
 843→        Some(Command::Chat { session, url }) => {
 844→            // File-based logging for TUI mode (don't clobber the terminal)
 845→            let log_dir = data_dir.join("logs");
 846→            std::fs::create_dir_all(&log_dir)?;
 847→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 848→            tracing_subscriber::fmt()
 849→                .with_writer(file_appender)
 850→                .with_env_filter(EnvFilter::from_default_env())
 851→                .init();
 852→
 853→            let resolved = config::resolve(
 854→                &file_config,
 855→                cli.provider.as_deref(),
 856→                cli.model.as_deref(),
 857→                cli.port,
 858→                None,
 859→                None,
 860→                cli.autonomic_url.as_deref(),
 861→            );
 862→
 863→            let runtime = tokio::runtime::Builder::new_multi_thread()
 864→                .enable_all()
 865→                .build()?;
 866→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
 867→        }
 868→        Some(Command::Login { provider, device }) => run_login(&provider, device, &data_dir),
 869→        Some(Command::Logout { provider }) => run_logout(&provider, &data_dir),
 870→        Some(Command::Api { url, output }) => {
 871→            let resolved = config::resolve(
 872→                &file_config,
 873→                cli.provider.as_deref(),
 874→                cli.model.as_deref(),
 875→                cli.port,
 876→                None,
 877→                None,
 878→                cli.autonomic_url.as_deref(),
 879→            );
 880→
 881→            let runtime = tokio::runtime::Builder::new_multi_thread()
 882→                .enable_all()
 883→                .build()?;
 884→            runtime.block_on(run_api(data_dir, &resolved, url, output))
 885→        }
 886→        Some(Command::Run {
 887→            message,
 888→            session,
 889→            url,
 890→            json,
 891→        }) => {
 892→            // File-based logging for CLI mode (don't clobber stdout)
 893→            let log_dir = data_dir.join("logs");
 894→            std::fs::create_dir_all(&log_dir)?;
 895→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
 896→            tracing_subscriber::fmt()
 897→                .with_writer(file_appender)
 898→                .with_env_filter(EnvFilter::from_default_env())
 899→                .init();
 900→
 901→            let resolved = config::resolve(
 902→                &file_config,
 903→                cli.provider.as_deref(),
 904→                cli.model.as_deref(),
 905→                cli.port,
 906→                None,
 907→                None,
 908→                cli.autonomic_url.as_deref(),
 909→            );
 910→
 911→            let runtime = tokio::runtime::Builder::new_multi_thread()
 912→                .enable_all()
 913→                .build()?;
 914→            runtime.block_on(run_message(
 915→                data_dir, &resolved, message, session, url, json,
 916→            ))
 917→        }
 918→        Some(Command::Config { action }) => run_config(&data_dir, action),
 919→        Some(Command::Status) => {
 920→            let resolved = config::resolve(
 921→                &file_config,
 922→                cli.provider.as_deref(),
 923→                cli.model.as_deref(),
 924→                cli.port,
 925→                None,
 926→                None,
 927→                cli.autonomic_url.as_deref(),
 928→            );
 929→
 930→            let runtime = tokio::runtime::Builder::new_multi_thread()
 931→                .enable_all()
 932→                .build()?;
 933→            runtime.block_on(run_status(&data_dir, &resolved))
 934→        }
 935→        Some(Command::Stop) => {
 936→            let resolved = config::resolve(
 937→                &file_config,
 938→                cli.provider.as_deref(),
 939→                cli.model.as_deref(),
 940→                cli.port,
 941→                None,
 942→                None,
 943→                cli.autonomic_url.as_deref(),
 944→            );
 945→
 946→            let runtime = tokio::runtime::Builder::new_multi_thread()
 947→                .enable_all()
 948→                .build()?;
 949→            runtime.block_on(daemon::stop_daemon(&data_dir, resolved.port))
 950→        }
 951→        None => {
 952→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
 953→            let log_dir = data_dir.join("logs");
 954→            std::fs::create_dir_all(&log_dir)?;
 955→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 956→            tracing_subscriber::fmt()
 957→                .with_writer(file_appender)
 958→                .with_env_filter(EnvFilter::from_default_env())
 959→                .init();
 960→
 961→            let resolved = config::resolve(
 962→                &file_config,
 963→                cli.provider.as_deref(),
 964→                cli.model.as_deref(),
 965→                cli.port,
 966→                None,
 967→                None,
 968→                cli.autonomic_url.as_deref(),
 969→            );
 970→
 971→            let runtime = tokio::runtime::Builder::new_multi_thread()
 972→                .enable_all()
 973→                .build()?;
 974→            runtime.block_on(run_chat(data_dir, &resolved, None, None))
 975→        }
 976→    }
 977→}
